        if let dict = value as? [String: Any] {
            if let pretty = prettyJSONString(from: dict) { return pretty }
            return "\(dict)"
        }
        if let arr = value as? [Any] {
            if let pretty = prettyJSONString(from: arr) { return pretty }
            return "\(arr)"
        }
        return String(describing: value)
    }

    private static func prettyJSONString(from object: Any) -> String? {
        guard JSONSerialization.isValidJSONObject(object) else { return nil }
        guard let data = try? JSONSerialization.data(withJSONObject: object, options: [.prettyPrinted, .sortedKeys]) else { return nil }
