// MARK: - URLSession Instrumentation

public final class AnalyticsDebugURLSessionDelegate: NSObject, URLSessionTaskDelegate, URLSessionDataDelegate {
    private let lock = NSLock()
    private var startTimes: [Int: CFAbsoluteTime] = [:]
    private var receivedData: [Int: Data] = [:]
    private var requestBodies: [Int: Data] = [:]
    private var userIdProvider: (() -> String?)?
    private var emailProvider: (() -> String?)?
    private var tokenProvider: (() -> String?)?

    public init(userIdProvider: (() -> String?)? = nil, emailProvider: (() -> String?)? = nil, tokenProvider: (() -> String?)? = nil) {
        self.userIdProvider = userIdProvider
        self.emailProvider = emailProvider
        self.tokenProvider = tokenProvider
    }

    public func urlSession(_ session: URLSession, task: URLSessionTask, didSendBodyData bytesSent: Int64, totalBytesSent: Int64, totalBytesExpectedToSend: Int64) {
        AnalyticsDebug.shared.log(
            .verbose,
            category: .api,
            name: "api.uploadProgress",
            message: "task=\(task.taskIdentifier) sent=\(totalBytesSent)/\(totalBytesExpectedToSend)",
            metadata: [
                "taskId": task.taskIdentifier,
                "bytesSent": bytesSent,
                "totalBytesSent": totalBytesSent,
                "totalBytesExpectedToSend": totalBytesExpectedToSend
            ]
        )
    }

    public func urlSession(_ session: URLSession, dataTask: URLSessionDataTask, didReceive data: Data) {
        lock.lock()
        var existing = receivedData[dataTask.taskIdentifier] ?? Data()
        existing.append(data)
        receivedData[dataTask.taskIdentifier] = existing
        lock.unlock()
    }

    public func urlSession(_ session: URLSession, task: URLSessionTask, didCompleteWithError error: Error?) {
        let taskId = task.taskIdentifier

        lock.lock()
        let start = startTimes[taskId]
        let data = receivedData[taskId]
        let reqBody = requestBodies[taskId]
        startTimes[taskId] = nil
        receivedData[taskId] = nil
        requestBodies[taskId] = nil
        lock.unlock()

        let durationMs: Double? = start.map { (CFAbsoluteTimeGetCurrent() - $0) * 1000.0 }

        let request = task.originalRequest
        let method = request?.httpMethod ?? "UNKNOWN"
        let url = request?.url?.absoluteString ?? "UNKNOWN"
        let headers = (request?.allHTTPHeaderFields ?? [:])

        var responseStatus: Int?
        var responseHeaders: [String: String]?
        if let http = task.response as? HTTPURLResponse {
            responseStatus = http.statusCode
            var h: [String: String] = [:]
            for (k, v) in http.allHeaderFields {
                if let ks = k as? String {
                    h[ks] = String(describing: v)
                }
            }
            responseHeaders = h
        }

        let query: [String: String] = {
            guard let u = request?.url, let comps = URLComponents(url: u, resolvingAgainstBaseURL: false) else { return [:] }
            var q: [String: String] = [:]
            for item in comps.queryItems ?? [] {
                q[item.name] = item.value ?? ""
            }
            return q
        }()

        let requestBodyAny: Any? = {
            if let b = request?.httpBody { return b }
            if let b = reqBody { return b }
            return nil
        }()

        let responseBodyAny: Any? = data

        let ctx = APICallContext(
            callId: UUID().uuidString,
            userId: userIdProvider?(),
            email: emailProvider?(),
            accessToken: tokenProvider?(),
            refreshToken: nil,
            method: method,
            url: url,
            headers: headers,
            query: query,
            requestBody: requestBodyAny,
            responseStatusCode: responseStatus,
            responseHeaders: responseHeaders,
            responseBody: responseBodyAny,
            durationMs: durationMs,
            extra: [
                "taskId": taskId
            ]
        )

        APIDebug.response(ctx, error: error)
    }

    public func urlSession(_ session: URLSession, task: URLSessionTask, needNewBodyStream completionHandler: @escaping (InputStream?) -> Void) {
        completionHandler(nil)
    }

    public func urlSession(_ session: URLSession, task: URLSessionTask, willBeginDelayedRequest request: URLRequest, completionHandler: @escaping (URLSession.DelayedRequestDisposition, URLRequest?) -> Void) {
        completionHandler(.continueLoading, nil)
    }

    public func urlSession(_ session: URLSession, task: URLSessionTask, didFinishCollecting metrics: URLSessionTaskMetrics) {
        let taskId = task.taskIdentifier
        lock.lock()
        startTimes[taskId] = CFAbsoluteTimeGetCurrent()
        lock.unlock()
    }

    public func urlSession(_ session: URLSession, task: URLSessionTask, didReceive challenge: URLAuthenticationChallenge, completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        AnalyticsDebug.shared.log(
            .info,
            category: .api,
            name: "api.authChallenge",
            message: "task=\(task.taskIdentifier) method=\(challenge.protectionSpace.authenticationMethod)",
            metadata: [
                "taskId": task.taskIdentifier,
                "host": challenge.protectionSpace.host,
                "realm": challenge.protectionSpace.realm as Any,
                "authMethod": challenge.protectionSpace.authenticationMethod
            ]
        )
        completionHandler(.performDefaultHandling, nil)
    }

    public func captureRequestBody(task: URLSessionTask, body: Data) {
        lock.lock()
        requestBodies[task.taskIdentifier] = body
        lock.unlock()
    }
}

// MARK: - UIKit Helpers

public final class AnalyticsDebugGestureTracker: NSObject {
    private weak var view: UIView?
    private var userIdProvider: (() -> String?)?
    private var emailProvider: (() -> String?)?
    private var tokenProvider: (() -> String?)?
    private var screenProvider: (() -> String)?

    public init(
        view: UIView,
        screenProvider: (() -> String)? = nil,
        userIdProvider: (() -> String?)? = nil,
        emailProvider: (() -> String?)? = nil,
        tokenProvider: (() -> String?)? = nil
    ) {
        self.view = view
        self.screenProvider = screenProvider
        self.userIdProvider = userIdProvider
        self.emailProvider = emailProvider
        self.tokenProvider = tokenProvider
        super.init()
        let tap = UITapGestureRecognizer(target: self, action: #selector(onTap(_:)))
        tap.cancelsTouchesInView = false
        view.addGestureRecognizer(tap)
    }

    @objc private func onTap(_ gr: UITapGestureRecognizer) {
        guard let view else { return }
        let point = gr.location(in: view)
        let hit = view.hitTest(point, with: nil)
        let element = hit.map { String(describing: type(of: $0)) } ?? "unknown"
        let screen = screenProvider?() ?? "unknown"

        let ctx = UIInteractionContext(
            userId: userIdProvider?(),
            email: emailProvider?(),
            screen: screen,
            element: element,
            action: "tap",
            value: [
                "x": point.x,
                "y": point.y
            ],
            token: tokenProvider?(),
            extra: [
                "accessibilityIdentifier": hit?.accessibilityIdentifier as Any,
                "accessibilityLabel": hit?.accessibilityLabel as Any
            ]
        )
        UIDebug.track(ctx)
    }
}

// MARK: - Convenience

public enum AnalyticsDebugConvenience {
    public static func logAuthStart(userId: String?, email: String?, provider: String?, token: String?) -> AuthContext {
        var ctx = AuthContext(provider: provider, userId: userId, email: email, accessToken: token)
        AuthDebug.track(.start, context: ctx, message: "Auth flow started")
        return ctx
    }

    public static func logAuthSuccess(_ ctx: AuthContext, userId: String?, email: String?, accessToken: String?, refreshToken: String?, idToken: String?) -> AuthContext {
        var updated = ctx
        updated.userId = userId ?? updated.userId
        updated.email = email ?? updated.email
        updated.accessToken = accessToken ?? updated.accessToken
        updated.refreshToken = refreshToken ?? updated.refreshToken
        updated.idToken = idToken ?? updated.idToken
        AuthDebug.track(.success, context: updated, message: "Auth success")
        return updated
    }

    public static func logAuthFailure(_ ctx: AuthContext, error: Error) {
        AuthDebug.track(.failure, context: ctx, message: "Auth failure", error: error)
    }
}